for key, content in replacements.items():
    # Replace 相性解説
    pattern_kaisetsu = re.compile(r'(## vs \[' + key + r'\].*?### 相性解説\n\n)(.*?)(?=\n\n### 一緒に楽しむコツ)', re.DOTALL)
    text = pattern_kaisetsu.sub(r'\1' + content["相性解説"] + '\n\n', text)
    
    # Replace 一緒に楽しむコツ
    pattern_kotsu = re.compile(r'(## vs \[' + key + r'\].*?### 一緒に楽しむコツ\n\n)(.*?)(?=\n\n### 摩擦ポイント)', re.DOTALL)
    text = pattern_kotsu.sub(r'\1' + content["一緒に楽しむコツ"] + '\n\n', text)
    
    # Replace 摩擦ポイント
    pattern_masatsu = re.compile(r'(## vs \[' + key + r'\].*?### 摩擦ポイント\n\n)(.*?)(?=\n\n### 目的の持ち方)', re.DOTALL)
    text = pattern_masatsu.sub(r'\1' + content["摩擦ポイント"] + '\n\n', text)

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(text)

